#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int max_score = 0;
        int winner = -1;
        int tie = 0;
        for (int i = 0; i < N; i++) {
            int c;
            scanf("%d", &c);
            int* type = (int*) malloc(c * sizeof(int));
            for (int j = 0; j < c; j++) {
                scanf("%d", &type[j]);
            }
            int score = c;
            int unique_types = 0;
            int* count = (int*) malloc(7 * sizeof(int));
            for (int j = 0; j < 7; j++) {
                count[j] = 0;
            }
            for (int j = 0; j < c; j++) {
                count[type[j]]++;
            }
            for (int j = 1; j < 7; j++) {
                if (count[j] > 0) {
                    unique_types++;
                }
            }
            if (unique_types == 4) {
                score++;
            } else if (unique_types == 5) {
                score += 2;
            } else if (unique_types == 6) {
                score += 4;
            }
            if (score > max_score) {
                max_score = score;
                winner = i + 1;
                tie = 0;
            } else if (score == max_score) {
                tie = 1;
            }
            free(type);
            free(count);
        }
        if (tie) {
            printf("tie\n");
        } else if (winner == 1) {
            printf("chef\n");
        } else {
            printf("%d\n", winner);
        }
    }
    return 0;
}

