import java.util.Scanner;
import java.util.HashSet;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int max_score = 0;
            int winner = -1;
            int tie = 0;
            for (int i = 0; i < N; i++) {
                int c = sc.nextInt();
                int[] type = new int[c];
                for (int j = 0; j < c; j++) {
                    type[j] = sc.nextInt();
                }
                int score = c;
                HashSet<Integer> unique_types = new HashSet<>();
                for (int j = 0; j < c; j++) {
                    unique_types.add(type[j]);
                }
                if (unique_types.size() == 4) {
                    score++;
                } else if (unique_types.size() == 5) {
                    score += 2;
                } else if (unique_types.size() == 6) {
                    score += 4;
                }
                if (score > max_score) {
                    max_score = score;
                    winner = i + 1;
                    tie = 0;
                } else if (score == max_score) {
                    tie = 1;
                }
            }
            if (tie > 0) {
                System.out.println("tie");
            } else if (winner == 1) {
                System.out.println("chef");
            } else {
                System.out.println(winner);
            }
        }
    }
}

